module RefModule(
    input clk,
    input reset,
    input enable,
    output reg [1:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) begin
            // Synchronous reset: Reset the counter to zero
            q <= 2'b00;
        end else if (enable) begin
            // Increment the counter by 1
            q <= q + 1;
        end
    end

endmodule
